"use client";

import { useState } from "react";
import { useTasks } from "@/contexts/TaskContext";
import { formatDateRelative, formatDateFull } from "@/lib/dateUtils";
import Lightbox from "@/components/ui/Lightbox";

export default function EvidenciasPage() {
  const { evidences, tasks } = useTasks();
  const [lightboxImg, setLightboxImg] = useState(null);
  const [filterStatus, setFilterStatus] = useState("todos");

  const filtered = filterStatus === "todos"
    ? evidences
    : evidences.filter((e) => (e.status || "pendente") === filterStatus);

  function getTaskTitle(taskId) {
    return tasks.find((t) => t.id === taskId)?.title || "Tarefa removida";
  }

  return (
    <div className="animate-fade">
      <div className="header">
        <div className="header-title">
          <h1>📸 Evidências Fotográficas</h1>
          <p>{filtered.length} evidência(s)</p>
        </div>
      </div>

      {/* Filters */}
      <div className="task-filters" style={{ marginBottom: 16 }}>
        {["todos", "pendente", "aprovada", "rejeitada"].map((s) => (
          <button
            key={s}
            className={`filter-chip ${filterStatus === s ? "active" : ""}`}
            onClick={() => setFilterStatus(s)}
          >
            {s === "todos" ? "Todas" : s === "pendente" ? "⏳ Pendentes" : s === "aprovada" ? "✅ Aprovadas" : "❌ Rejeitadas"}
          </button>
        ))}
      </div>

      {filtered.length > 0 ? (
        <div className="evidence-grid">
          {filtered.map((ev) => (
            <div key={ev.id} className="evidence-card" onClick={() => setLightboxImg(ev)}>
              <img src={ev.image_url} alt={ev.description || "Evidência"} />
              <span className={`evidence-status ${ev.status || "pendente"}`}>
                {ev.status === "aprovada" ? "✅" : ev.status === "rejeitada" ? "❌" : "⏳"}
              </span>
              <div className="evidence-card-overlay">
                <div style={{ fontWeight: 500 }}>{ev.description || "Sem descrição"}</div>
                <div style={{ fontSize: "0.65rem", opacity: 0.8 }}>
                  {getTaskTitle(ev.task_id)} • {formatDateRelative(ev.captured_at || ev.created_at)}
                </div>
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div className="empty-state">
          <div className="empty-state-icon">📷</div>
          <div className="empty-state-text">Nenhuma evidência encontrada</div>
          <div className="empty-state-sub">As evidências aparecerão aqui quando enviadas</div>
        </div>
      )}

      <Lightbox
        isOpen={!!lightboxImg}
        onClose={() => setLightboxImg(null)}
        src={lightboxImg?.image_url}
        alt={lightboxImg?.description}
        info={
          lightboxImg && (
            <div>
              <div style={{ fontWeight: 600, marginBottom: 4 }}>{lightboxImg.description || "Sem descrição"}</div>
              <div style={{ fontSize: "0.8rem", opacity: 0.8 }}>
                Tarefa: {getTaskTitle(lightboxImg.task_id)}
              </div>
              <div style={{ fontSize: "0.8rem", opacity: 0.8 }}>
                Por: {lightboxImg.captured_by} • {formatDateFull(lightboxImg.captured_at || lightboxImg.created_at)}
              </div>
              {lightboxImg.rejection_reason && (
                <div style={{ marginTop: 8, padding: "8px 12px", background: "rgba(198,40,40,0.2)", borderRadius: 8, fontSize: "0.85rem" }}>
                  ❌ Motivo: {lightboxImg.rejection_reason}
                </div>
              )}
            </div>
          )
        }
      />
    </div>
  );
}

"use client";

import { useAuth } from "@/contexts/AuthContext";
import { useTasks } from "@/contexts/TaskContext";
import { TASK_CATEGORIES } from "@/config/tasks.config";
import { formatDateRelative } from "@/lib/dateUtils";

export default function PainelPage() {
  const { user, isGerente } = useAuth();
  const { tasks, evidences, stats, loading } = useTasks();

  if (loading) {
    return (
      <div className="animate-fade">
        <div className="header"><div className="header-title"><h1>Carregando...</h1></div></div>
        <div className="stats-grid">
          {[1, 2, 3, 4].map((i) => (<div key={i} className="stat-card skeleton" style={{ height: 100 }} />))}
        </div>
      </div>
    );
  }

  // Tarefas por categoria
  const tasksByCategory = TASK_CATEGORIES.map((cat) => ({
    ...cat,
    count: tasks.filter((t) => t.category === cat.id).length,
  })).filter((c) => c.count > 0);

  // Tarefas urgentes
  const urgentTasks = tasks.filter((t) => t.priority === "urgente" && t.status !== "concluida");

  // Evidências recentes pendentes
  const pendingEvidences = evidences.filter((e) => e.status === "pendente").slice(0, 5);

  return (
    <div className="animate-fade">
      <div className="header">
        <div className="header-title">
          <h1>Olá, {user?.name} 👋</h1>
          <p>{isGerente ? "Visão geral do sistema" : "Suas tarefas de hoje"}</p>
        </div>
      </div>

      {/* Stats */}
      <div className="stats-grid">
        <div className="stat-card">
          <div className="stat-icon">📋</div>
          <div className="stat-number" style={{ color: "var(--text-primary)" }}>{stats.total}</div>
          <div className="stat-label">Total</div>
        </div>
        <div className="stat-card">
          <div className="stat-icon">⏳</div>
          <div className="stat-number" style={{ color: "var(--color-warning)" }}>{stats.pendentes}</div>
          <div className="stat-label">Pendentes</div>
        </div>
        <div className="stat-card">
          <div className="stat-icon">🔄</div>
          <div className="stat-number" style={{ color: "var(--color-info)" }}>{stats.emAndamento}</div>
          <div className="stat-label">Em Andamento</div>
        </div>
        <div className="stat-card">
          <div className="stat-icon">📸</div>
          <div className="stat-number" style={{ color: "#FF9800" }}>{stats.aguardando}</div>
          <div className="stat-label">Aguardando</div>
        </div>
        <div className="stat-card">
          <div className="stat-icon">✅</div>
          <div className="stat-number" style={{ color: "var(--color-success)" }}>{stats.concluidas}</div>
          <div className="stat-label">Concluídas</div>
        </div>
        <div className="stat-card">
          <div className="stat-icon">📊</div>
          <div className="stat-number" style={{ color: "var(--color-primary)" }}>{stats.taxaConclusao}%</div>
          <div className="stat-label">Taxa de Conclusão</div>
        </div>
      </div>

      {/* Tarefas por categoria */}
      {tasksByCategory.length > 0 && (
        <div className="detail-section">
          <h2 className="detail-section-title">📂 Tarefas por Categoria</h2>
          <div style={{ display: "flex", flexWrap: "wrap", gap: 8 }}>
            {tasksByCategory.map((cat) => (
              <div key={cat.id} className="card" style={{ padding: "12px 16px", minWidth: 140, flex: "1 1 auto" }}>
                <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                  <span style={{ fontSize: "1.3rem" }}>{cat.icon}</span>
                  <div>
                    <div style={{ fontWeight: 700, fontSize: "1.1rem" }}>{cat.count}</div>
                    <div style={{ fontSize: "0.75rem", color: "var(--text-muted)" }}>{cat.label}</div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Urgentes */}
      {urgentTasks.length > 0 && (
        <div className="detail-section">
          <h2 className="detail-section-title">🚨 Tarefas Urgentes</h2>
          <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
            {urgentTasks.map((task) => (
              <div key={task.id} className="card" style={{ padding: "12px 16px", borderLeft: "4px solid var(--color-danger)" }}>
                <div style={{ fontWeight: 600, fontSize: "0.9rem" }}>{task.title}</div>
                <div style={{ fontSize: "0.8rem", color: "var(--text-muted)", marginTop: 4 }}>
                  {task.assigned_to_name || "Não atribuída"} • {formatDateRelative(task.created_at)}
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Evidências pendentes (gerente) */}
      {isGerente && pendingEvidences.length > 0 && (
        <div className="detail-section">
          <h2 className="detail-section-title">📸 Evidências Aguardando Aprovação</h2>
          <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
            {pendingEvidences.map((ev) => (
              <div key={ev.id} className="card" style={{ padding: "12px 16px", display: "flex", alignItems: "center", gap: 12 }}>
                <img src={ev.image_url} alt="" style={{ width: 48, height: 48, borderRadius: 8, objectFit: "cover" }} />
                <div style={{ flex: 1 }}>
                  <div style={{ fontWeight: 500, fontSize: "0.85rem" }}>{ev.description || "Sem descrição"}</div>
                  <div style={{ fontSize: "0.75rem", color: "var(--text-muted)" }}>{formatDateRelative(ev.captured_at || ev.created_at)}</div>
                </div>
                <span className="badge badge-sm" style={{ background: "#FF980020", color: "#FF9800" }}>Pendente</span>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Empty state */}
      {tasks.length === 0 && (
        <div className="empty-state">
          <div className="empty-state-icon">📋</div>
          <div className="empty-state-text">Nenhuma tarefa ainda</div>
          <div className="empty-state-sub">
            {isGerente ? "Crie a primeira tarefa na aba Tarefas" : "Aguarde o gerente criar tarefas"}
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import { useState } from "react";
import { useRouter, useParams } from "next/navigation";
import { useAuth } from "@/contexts/AuthContext";
import { useTasks } from "@/contexts/TaskContext";
import { useToast } from "@/contexts/ToastContext";
import { getCategoryById, getPriorityById, getStatusById, TASK_STATUSES } from "@/config/tasks.config";
import { formatDateFull, formatDateRelative } from "@/lib/dateUtils";
import PhotoCapture from "@/components/evidence/PhotoCapture";
import Lightbox from "@/components/ui/Lightbox";
import Modal from "@/components/ui/Modal";

export default function TaskDetailPage() {
  const { id } = useParams();
  const router = useRouter();
  const { user, isGerente } = useAuth();
  const { getTaskById, getEvidencesByTask, updateTask, deleteTask, addEvidence, approveEvidence, rejectEvidence } = useTasks();
  const toast = useToast();

  const [showCapture, setShowCapture] = useState(false);
  const [lightboxImg, setLightboxImg] = useState(null);
  const [rejectModal, setRejectModal] = useState(null);
  const [rejectReason, setRejectReason] = useState("");

  const task = getTaskById(id);
  const taskEvidences = getEvidencesByTask(id);

  if (!task) {
    return (
      <div className="empty-state animate-fade">
        <div className="empty-state-icon">🔍</div>
        <div className="empty-state-text">Tarefa não encontrada</div>
        <button className="btn btn-primary" style={{ marginTop: 16 }} onClick={() => router.push("/tarefas")}>
          Voltar para Tarefas
        </button>
      </div>
    );
  }

  const category = getCategoryById(task.category);
  const priority = getPriorityById(task.priority);
  const status = getStatusById(task.status);

  async function handleStatusChange(newStatus) {
    await updateTask(task.id, { status: newStatus });
    toast.success(`Status atualizado para "${getStatusById(newStatus).label}"`);
  }

  async function handleDelete() {
    if (confirm("Tem certeza que deseja excluir esta tarefa?")) {
      await deleteTask(task.id);
      toast.success("Tarefa excluída");
      router.push("/tarefas");
    }
  }

  async function handleEvidenceCapture(evidenceData) {
    const result = await addEvidence({ ...evidenceData, captured_by: user?.name });
    if (result) {
      toast.success("Evidência enviada com sucesso!");
      setShowCapture(false);
    }
  }

  async function handleApprove(evId) {
    await approveEvidence(evId, task.id);
    toast.success("Evidência aprovada!");
  }

  async function handleReject() {
    if (!rejectModal) return;
    await rejectEvidence(rejectModal, task.id, rejectReason);
    toast.warning("Evidência rejeitada. Tarefa devolvida.");
    setRejectModal(null);
    setRejectReason("");
  }

  return (
    <div className="animate-fade">
      {/* Header */}
      <div className="detail-header">
        <button className="back-btn" onClick={() => router.push("/tarefas")}>←</button>
        <div style={{ flex: 1 }}>
          <h1 style={{ fontSize: "1.2rem" }}>{task.title}</h1>
          <div style={{ display: "flex", gap: 8, marginTop: 6, flexWrap: "wrap" }}>
            <span className="badge" style={{ background: `${status.color}18`, color: status.color }}>
              {status.icon} {status.label}
            </span>
            <span className="badge" style={{ background: `${priority.color}18`, color: priority.color }}>
              {priority.label}
            </span>
            <span className="badge" style={{ background: `${category.color}18`, color: category.color }}>
              {category.icon} {category.label}
            </span>
          </div>
        </div>
      </div>

      {/* Info */}
      <div className="detail-section">
        <h3 className="detail-section-title">📋 Informações</h3>
        {task.description && (
          <p style={{ fontSize: "0.9rem", color: "var(--text-secondary)", marginBottom: 16, lineHeight: 1.5 }}>
            {task.description}
          </p>
        )}
        <div className="detail-info-grid">
          <div className="detail-info-item">
            <div className="detail-info-label">Criada por</div>
            <div className="detail-info-value">{task.created_by_name || "—"}</div>
          </div>
          <div className="detail-info-item">
            <div className="detail-info-label">Atribuída para</div>
            <div className="detail-info-value">{task.assigned_to_name || "Não atribuída"}</div>
          </div>
          <div className="detail-info-item">
            <div className="detail-info-label">Criada em</div>
            <div className="detail-info-value">{formatDateFull(task.created_at)}</div>
          </div>
          <div className="detail-info-item">
            <div className="detail-info-label">Prazo</div>
            <div className="detail-info-value">{task.due_date || "Sem prazo"}</div>
          </div>
        </div>
      </div>

      {/* Actions */}
      <div className="detail-section">
        <h3 className="detail-section-title">⚡ Ações</h3>
        <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
          {/* Funcionário pode mudar status */}
          {!isGerente && task.status === "pendente" && (
            <button className="btn btn-primary btn-sm" onClick={() => handleStatusChange("em_andamento")}>
              🔄 Iniciar Tarefa
            </button>
          )}
          {!isGerente && task.status === "em_andamento" && (
            <button className="btn btn-success btn-sm" onClick={() => setShowCapture(true)}>
              📸 Enviar Evidência
            </button>
          )}
          {!isGerente && task.status === "rejeitada" && (
            <button className="btn btn-primary btn-sm" onClick={() => handleStatusChange("em_andamento")}>
              🔄 Refazer Tarefa
            </button>
          )}

          {/* Gerente pode gerenciar */}
          {isGerente && (
            <>
              <select
                className="select"
                style={{ width: "auto", padding: "6px 12px", fontSize: "0.85rem" }}
                value={task.status}
                onChange={(e) => handleStatusChange(e.target.value)}
              >
                {TASK_STATUSES.map((s) => (
                  <option key={s.id} value={s.id}>{s.icon} {s.label}</option>
                ))}
              </select>
              <button className="btn btn-danger btn-sm" onClick={handleDelete}>🗑️ Excluir</button>
            </>
          )}
        </div>
      </div>

      {/* Photo Capture */}
      {showCapture && (
        <div className="detail-section animate-slide">
          <h3 className="detail-section-title">📸 Capturar Evidência</h3>
          <PhotoCapture onCapture={handleEvidenceCapture} taskId={task.id} />
        </div>
      )}

      {/* Evidências */}
      <div className="detail-section">
        <h3 className="detail-section-title">📸 Evidências ({taskEvidences.length})</h3>

        {taskEvidences.length > 0 ? (
          <div className="evidence-grid">
            {taskEvidences.map((ev) => (
              <div key={ev.id} className="evidence-card" onClick={() => setLightboxImg(ev)}>
                <img src={ev.image_url} alt={ev.description || "Evidência"} />
                <span className={`evidence-status ${ev.status || "pendente"}`}>
                  {ev.status === "aprovada" ? "✅ Aprovada" : ev.status === "rejeitada" ? "❌ Rejeitada" : "⏳ Pendente"}
                </span>
                <div className="evidence-card-overlay">
                  <div>{ev.description || "Sem descrição"}</div>
                  <div style={{ fontSize: "0.65rem", opacity: 0.8 }}>{formatDateRelative(ev.captured_at || ev.created_at)}</div>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="empty-state" style={{ padding: 24 }}>
            <div className="empty-state-icon">📷</div>
            <div className="empty-state-text">Nenhuma evidência enviada</div>
          </div>
        )}

        {/* Approve/Reject buttons for gerente */}
        {isGerente && taskEvidences.filter((e) => e.status === "pendente").length > 0 && (
          <div style={{ marginTop: 16, display: "flex", flexDirection: "column", gap: 8 }}>
            <h4 style={{ fontSize: "0.9rem", fontWeight: 600 }}>Aprovar/Rejeitar evidências pendentes:</h4>
            {taskEvidences.filter((e) => e.status === "pendente").map((ev) => (
              <div key={ev.id} className="card" style={{ display: "flex", alignItems: "center", gap: 12, padding: 12 }}>
                <img src={ev.image_url} alt="" style={{ width: 50, height: 50, borderRadius: 8, objectFit: "cover" }} />
                <div style={{ flex: 1, fontSize: "0.85rem" }}>{ev.description || "Sem descrição"}</div>
                <button className="btn btn-success btn-sm" onClick={() => handleApprove(ev.id)}>✅</button>
                <button className="btn btn-danger btn-sm" onClick={() => setRejectModal(ev.id)}>❌</button>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Lightbox */}
      <Lightbox
        isOpen={!!lightboxImg}
        onClose={() => setLightboxImg(null)}
        src={lightboxImg?.image_url}
        alt={lightboxImg?.description}
        info={
          lightboxImg && (
            <div>
              <div style={{ fontWeight: 600 }}>{lightboxImg.description || "Sem descrição"}</div>
              <div style={{ fontSize: "0.8rem", opacity: 0.8, marginTop: 4 }}>
                {lightboxImg.captured_by} • {formatDateFull(lightboxImg.captured_at || lightboxImg.created_at)}
              </div>
              {lightboxImg.rejection_reason && (
                <div style={{ marginTop: 8, padding: "8px 12px", background: "rgba(198,40,40,0.2)", borderRadius: 8, fontSize: "0.85rem" }}>
                  ❌ Motivo: {lightboxImg.rejection_reason}
                </div>
              )}
            </div>
          )
        }
      />

      {/* Reject Modal */}
      <Modal
        isOpen={!!rejectModal}
        onClose={() => { setRejectModal(null); setRejectReason(""); }}
        title="Rejeitar Evidência"
        footer={
          <>
            <button className="btn btn-secondary" onClick={() => { setRejectModal(null); setRejectReason(""); }}>Cancelar</button>
            <button className="btn btn-danger" onClick={handleReject}>Rejeitar</button>
          </>
        }
      >
        <div className="input-group">
          <label>Motivo da rejeição</label>
          <textarea
            className="textarea"
            value={rejectReason}
            onChange={(e) => setRejectReason(e.target.value)}
            placeholder="Explique por que a evidência foi rejeitada..."
          />
        </div>
      </Modal>
    </div>
  );
}

"use client";

import { useRef, useState } from "react";
import { compressImage, fileToBase64 } from "@/lib/imageUtils";

export default function PhotoCapture({ onCapture, taskId }) {
  const fileInputRef = useRef(null);
  const [preview, setPreview] = useState(null);
  const [description, setDescription] = useState("");
  const [loading, setLoading] = useState(false);

  async function handleFileChange(e) {
    const file = e.target.files?.[0];
    if (!file) return;

    setLoading(true);
    try {
      const compressed = await compressImage(file, { maxWidth: 1200, quality: 0.7 });
      const base64 = await fileToBase64(compressed);
      setPreview(base64);
    } catch (err) {
      console.error("Erro ao processar imagem:", err);
    } finally {
      setLoading(false);
    }
  }

  function handleSubmit() {
    if (!preview) return;
    onCapture({
      image_url: preview,
      description,
      task_id: taskId,
      status: "pendente",
      captured_at: new Date().toISOString(),
    });
    setPreview(null);
    setDescription("");
  }

  function handleRemovePreview() {
    setPreview(null);
    setDescription("");
    if (fileInputRef.current) fileInputRef.current.value = "";
  }

  return (
    <div className="animate-fade">
      <input
        ref={fileInputRef}
        type="file"
        accept="image/*"
        capture="environment"
        onChange={handleFileChange}
        style={{ display: "none" }}
      />

      {!preview ? (
        <div className="photo-capture" onClick={() => fileInputRef.current?.click()}>
          {loading ? (
            <>
              <div className="photo-capture-icon">⏳</div>
              <div className="photo-capture-text">Processando imagem...</div>
            </>
          ) : (
            <>
              <div className="photo-capture-icon">📸</div>
              <div className="photo-capture-text">
                Toque para tirar foto ou selecionar da galeria
              </div>
            </>
          )}
        </div>
      ) : (
        <div>
          <div className="photo-preview">
            <img src={preview} alt="Preview da evidência" />
            <button className="photo-preview-remove" onClick={handleRemovePreview}>✕</button>
          </div>

          <div className="input-group" style={{ marginTop: 12 }}>
            <label>Descrição da evidência</label>
            <textarea
              className="textarea"
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              placeholder="Descreva o que a foto mostra..."
              rows={2}
            />
          </div>

          <button className="btn btn-success w-full" style={{ marginTop: 12 }} onClick={handleSubmit}>
            ✅ Enviar Evidência
          </button>
        </div>
      )}
    </div>
  );
}

"use client";

export default function Lightbox({ isOpen, onClose, src, alt, info }) {
  if (!isOpen) return null;

  return (
    <div className="lightbox" onClick={onClose}>
      <button className="lightbox-close" onClick={onClose}>✕</button>
      <img src={src} alt={alt || "Evidência"} onClick={(e) => e.stopPropagation()} />
      {info && (
        <div className="lightbox-info" onClick={(e) => e.stopPropagation()}>
          {info}
        </div>
      )}
    </div>
  );
}

"use client";

import { createContext, useContext, useState, useEffect, useCallback } from "react";
import { storage } from "@/lib/storage";

const TaskContext = createContext(null);

export function TaskProvider({ children }) {
  const [tasks, setTasks] = useState([]);
  const [evidences, setEvidences] = useState([]);
  const [loading, setLoading] = useState(true);

  // Carregar dados iniciais
  const loadData = useCallback(async () => {
    setLoading(true);
    try {
      const [taskList, evidenceList] = await Promise.all([
        storage.getTasks(),
        storage.getEvidences(),
      ]);
      setTasks(taskList || []);
      setEvidences(evidenceList || []);
    } catch (e) {
      console.error("Erro ao carregar dados:", e);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    loadData();
  }, [loadData]);

  // ── CRUD de Tarefas ──

  const createTask = useCallback(async (taskData) => {
    const newTask = await storage.createTask({
      ...taskData,
      status: "pendente",
      evidence_count: 0,
    });
    if (newTask) {
      setTasks((prev) => [newTask, ...prev]);
    }
    return newTask;
  }, []);

  const updateTask = useCallback(async (id, updates) => {
    const updated = await storage.updateTask(id, updates);
    if (updated) {
      setTasks((prev) => prev.map((t) => (t.id === id ? { ...t, ...updated } : t)));
    }
    return updated;
  }, []);

  const deleteTask = useCallback(async (id) => {
    const success = await storage.deleteTask(id);
    if (success) {
      setTasks((prev) => prev.filter((t) => t.id !== id));
    }
    return success;
  }, []);

  // ── CRUD de Evidências ──

  const addEvidence = useCallback(async (evidenceData) => {
    const newEvidence = await storage.createEvidence(evidenceData);
    if (newEvidence) {
      setEvidences((prev) => [newEvidence, ...prev]);
      // Atualizar contagem de evidências na tarefa
      const task = tasks.find((t) => t.id === evidenceData.task_id);
      if (task) {
        await storage.updateTask(task.id, {
          evidence_count: (task.evidence_count || 0) + 1,
          status: "aguardando_evidencia",
        });
        setTasks((prev) =>
          prev.map((t) =>
            t.id === task.id
              ? { ...t, evidence_count: (t.evidence_count || 0) + 1, status: "aguardando_evidencia" }
              : t
          )
        );
      }
    }
    return newEvidence;
  }, [tasks]);

  const approveEvidence = useCallback(async (evidenceId, taskId) => {
    const updated = await storage.updateEvidence(evidenceId, { status: "aprovada" });
    if (updated) {
      setEvidences((prev) => prev.map((e) => (e.id === evidenceId ? { ...e, status: "aprovada" } : e)));
      // Verificar se todas as evidências da tarefa foram aprovadas
      const taskEvidences = evidences.filter((e) => e.task_id === taskId);
      const allApproved = taskEvidences.every((e) => e.id === evidenceId ? true : e.status === "aprovada");
      if (allApproved) {
        await updateTask(taskId, { status: "concluida" });
      }
    }
    return updated;
  }, [evidences, updateTask]);

  const rejectEvidence = useCallback(async (evidenceId, taskId, reason) => {
    const updated = await storage.updateEvidence(evidenceId, { status: "rejeitada", rejection_reason: reason });
    if (updated) {
      setEvidences((prev) => prev.map((e) => (e.id === evidenceId ? { ...e, status: "rejeitada", rejection_reason: reason } : e)));
      await updateTask(taskId, { status: "rejeitada" });
    }
    return updated;
  }, [updateTask]);

  // Upload de imagem para evidência
  const uploadEvidenceImage = useCallback(async (file, taskId) => {
    return await storage.uploadImage(file, taskId);
  }, []);

  // ── Helpers / Computed ──

  const getTaskById = useCallback((id) => {
    return tasks.find((t) => t.id === id);
  }, [tasks]);

  const getEvidencesByTask = useCallback((taskId) => {
    return evidences.filter((e) => e.task_id === taskId);
  }, [evidences]);

  const stats = {
    total: tasks.length,
    pendentes: tasks.filter((t) => t.status === "pendente").length,
    emAndamento: tasks.filter((t) => t.status === "em_andamento").length,
    aguardando: tasks.filter((t) => t.status === "aguardando_evidencia").length,
    concluidas: tasks.filter((t) => t.status === "concluida").length,
    rejeitadas: tasks.filter((t) => t.status === "rejeitada").length,
    taxaConclusao: tasks.length > 0
      ? Math.round((tasks.filter((t) => t.status === "concluida").length / tasks.length) * 100)
      : 0,
  };

  return (
    <TaskContext.Provider
      value={{
        tasks,
        evidences,
        loading,
        stats,
        createTask,
        updateTask,
        deleteTask,
        addEvidence,
        approveEvidence,
        rejectEvidence,
        uploadEvidenceImage,
        getTaskById,
        getEvidencesByTask,
        loadData,
      }}
    >
      {children}
    </TaskContext.Provider>
  );
}

export function useTasks() {
  const ctx = useContext(TaskContext);
  if (!ctx) throw new Error("useTasks deve ser usado dentro de TaskProvider");
  return ctx;
}
